export class SimplifyFrameTransformer extends OperationNodeTransformer {
  protected override transformOver(
    node: OverNode,
    queryId: QueryId,
  ): OverNode {
    const transformed = super.transformOver(node, queryId)

    if (
      transformed.frame &&
      this.#isRedundantFrame(transformed.frame, !!transformed.orderBy)
    ) {
      const { frame, ...rest } = transformed
      return freeze(rest)
    }

    return transformed
  }

  #isRedundantFrame(frame: FrameNode, hasOrderBy: boolean): boolean {
    if (frame.unit !== 'range' || frame.exclusion || !frame.end) {
      return false
    }

    if (!this.#isBound(frame.start, 'preceding', true)) {
      return false
    }

    return hasOrderBy
      ? this.#isBound(frame.end, 'current row')
      : this.#isBound(frame.end, 'following', true)
  }

  #isBound(
    bound: FrameBoundNode,
    type: FrameBoundNode['type'],
    unbounded = false,
  ): boolean {
    return (
      bound.type === type && !!bound.unbounded === unbounded && !bound.offset
    )
  }
}
