import { SimplifyFrameTransformer } from './simplify-frame-transformer.js'

/**
 * Plugin that removes over-clause frame extents that merely restate the
 * SQL-standard implicit default, keeping generated queries free of noise.
 *
 * When an `over` clause has an `order by`, the implicit default frame is
 * `range between unbounded preceding and current row`. When it has no
 * `order by`, the implicit default is
 * `range between unbounded preceding and unbounded following`.
 *
 * Extents that use `rows` or `groups` mode, carry an exclusion clause, or
 * have non-default bound types or expression-based offsets are left
 * untouched.
 *
 * ### Examples
 *
 * ```ts
 * import { Kysely, SimplifyFramePlugin } from 'kysely'
 *
 * const db = new Kysely<DB>({
 *   dialect,
 *   plugins: [new SimplifyFramePlugin()],
 * })
 * ```
 */
export class SimplifyFramePlugin implements KyselyPlugin {
  readonly #transformer = new SimplifyFrameTransformer()

  transformQuery(args: PluginTransformQueryArgs): RootOperationNode {
    return this.#transformer.transformNode(args.node, args.queryId)
  }

  transformResult(
    args: PluginTransformResultArgs,
  ): Promise<QueryResult<UnknownRow>> {
    return Promise.resolve(args.result)
  }
}
